     1→/**
     2→ * InfiniteCanvas - Professional-grade pan/zoom canvas
     3→ *
     4→ * Features:
     5→ * - Pan with mouse drag (bounded to world limits)
     6→ * - Zoom with scroll wheel (centers on cursor position)
     7→ * - Initial view shows top-left of data (X=0, Y=0)
     8→ * - Sidebar sync via onViewportChange callback
     9→ *
    10→ * Coordinate System:
    11→ * - X: 0 = first day, positive = future (right)
    12→ * - Y: 0 = first train (TRAIN-001), negative = more trains (down)
    13→ *
    14→ * References:
    15→ * - D3.js zoom: https://d3js.org/d3-zoom
    16→ * - Three.js OrthographicCamera: https://threejs.org/docs/api/en/cameras/OrthographicCamera.html
    17→ * - pixi-viewport: https://github.com/pixijs-userland/pixi-viewport
    18→ */
    19→
    20→import { Canvas, useThree } from '@react-three/fiber';
    21→import { useState, useCallback, useMemo, useEffect, useRef } from 'react';
    22→import { MesoLayer } from './layers/MesoLayer';
    23→import { MacroLayer } from './layers/MacroLayer';
    24→import { MicroLayer } from './layers/MicroLayer';
    25→import { getRenderData } from '../data/generator';
    26→import type { LODLevel, WorldBounds } from '../data/types';
    27→import { DEFAULT_VIEW_CONFIG, calculateWorldBounds } from '../data/types';
    28→
    29→// ─────────────────────────────────────────────────────────────
    30→// EXPORTED TYPES
    31→// ─────────────────────────────────────────────────────────────
    32→
    33→/**
    34→ * Viewport information passed to parent component
    35→ */
    36→export interface ViewportInfo {
    37→  /** Y coordinate of the TOP of the viewport in world space */
    38→  topY: number;
    39→  /** Left edge of the viewport in world X coordinates */
    40→  leftX: number;
    41→  /** Right edge of the viewport in world X coordinates */
    42→  rightX: number;
    43→}
    44→
    45→/**
    46→ * Viewport bounds in world coordinates
    47→ * Used for frustum culling - only render tasks within these bounds
    48→ */
    49→export interface ViewportBounds {
    50→  minX: number;
    51→  maxX: number;
    52→  minY: number;
    53→  maxY: number;
    54→}
    55→
    56→// ─────────────────────────────────────────────────────────────
    57→// LOD CONFIGURATION
    58→// ─────────────────────────────────────────────────────────────
    59→
    60→/**
    61→ * LOD Transition Configuration
    62→ *
    63→ * Defines blend zones around LOD thresholds for smooth transitions.
    64→ * During blend zones, both adjacent layers render with interpolated opacity.
    65→ */
    66→const LOD_THRESHOLDS = {
    67→  macroToMeso: 0.5,  // Below 0.5 = MACRO
    68→  mesoToMicro: 2.0,  // Above 2.0 = MICRO
    69→};
    70→
    71→// Size of blend zone around each threshold (±this value)
    72→const BLEND_ZONE_SIZE = 0.15;
    73→
    74→/**
    75→ * Calculate layer opacities for smooth LOD transitions
    76→ *
    77→ * Returns opacity values for each layer (0-1).
    78→ * During blend zones, adjacent layers overlap with interpolated opacity.
    79→ */
    80→function calculateLayerOpacities(zoom: number): {
    81→  macro: number;
    82→  meso: number;
    83→  micro: number;
    84→} {
    85→  const { macroToMeso, mesoToMicro } = LOD_THRESHOLDS;
    86→
    87→  // Define blend zone boundaries
    88→  const macroEnd = macroToMeso - BLEND_ZONE_SIZE; // 0.35
    89→  const mesoStart = macroToMeso + BLEND_ZONE_SIZE; // 0.65
    90→  const mesoEnd = mesoToMicro - BLEND_ZONE_SIZE; // 1.85
    91→  const microStart = mesoToMicro + BLEND_ZONE_SIZE; // 2.15
    92→
    93→  let macro = 0;
    94→  let meso = 0;
    95→  let micro = 0;
    96→
    97→  // Calculate MACRO opacity
    98→  if (zoom <= macroEnd) {
    99→    macro = 1;
   100→  } else if (zoom < mesoStart) {
   101→    // Blend zone MACRO → MESO
   102→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   103→    macro = 1 - t;
   104→  }
   105→
   106→  // Calculate MESO opacity
   107→  if (zoom < macroEnd) {
   108→    meso = 0;
   109→  } else if (zoom < mesoStart) {
   110→    // Blend zone MACRO → MESO
   111→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   112→    meso = t;
   113→  } else if (zoom <= mesoEnd) {
   114→    meso = 1;
   115→  } else if (zoom < microStart) {
   116→    // Blend zone MESO → MICRO
   117→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
   118→    meso = 1 - t;
   119→  }
   120→
   121→  // Calculate MICRO opacity
   122→  if (zoom <= mesoEnd) {
   123→    micro = 0;
   124→  } else if (zoom < microStart) {
   125→    // Blend zone MESO → MICRO
   126→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
   127→    micro = t;
   128→  } else {
   129→    micro = 1;
   130→  }
   131→
   132→  return { macro, meso, micro };
   133→}
   134→
   135→/**
   136→ * LODLayers - Orchestrates layer rendering with smooth transitions
   137→ *
   138→ * Renders multiple layers simultaneously during blend zones,
   139→ * with opacity interpolation for smooth visual transitions.
   140→ */
   141→function LODLayers({
   142→  tasks,
   143→  trainCount,
   144→  zoom,
   145→  viewportBounds,
   146→}: {
   147→  tasks: ReturnType<typeof getRenderData>['tasks'];
   148→  trainCount: number;
   149→  zoom: number;
   150→  viewportBounds: ViewportBounds;
   151→}) {
   152→  const opacities = useMemo(() => calculateLayerOpacities(zoom), [zoom]);
   153→
   154→  return (
   155→    <group>
   156→      {/* Render each layer if opacity > 0 */}
   157→      {opacities.macro > 0 && (
   158→        <MacroLayer
   159→          tasks={tasks}
   160→          trainCount={trainCount}
   161→          opacity={opacities.macro}
   162→        />
   163→      )}
   164→      {opacities.meso > 0 && (
   165→        <MesoLayer
   166→          tasks={tasks}
   167→          trainCount={trainCount}
   168→          opacity={opacities.meso}
   169→        />
   170→      )}
   171→      {opacities.micro > 0 && (
   172→        <MicroLayer
   173→          tasks={tasks}
   174→          trainCount={trainCount}
   175→          opacity={opacities.micro}
   176→          viewportBounds={viewportBounds}
   177→        />
   178→      )}
   179→    </group>
   180→  );
   181→}
   182→
   183→interface InfiniteCanvasProps {
   184→  zoom: number;
   185→  lod: LODLevel;
   186→  onZoomChange: (zoom: number) => void;
   187→  /**
   188→   * Called when viewport position changes.
   189→   * @param viewport - Object with topY, leftX, rightX coordinates
   190→   */
   191→  onViewportChange?: (viewport: ViewportInfo) => void;
   192→  /**
   193→   * Called when the effective minimum zoom changes.
   194→   * Used by parent to enforce zoom limits on buttons.
   195→   */
   196→  onMinZoomChange?: (minZoom: number) => void;
   197→  /**
   198→   * Request a smooth animated zoom to target level.
   199→   * Called by parent buttons for +/- zoom with animation.
   200→   */
   201→  animatedZoomTarget?: number | null;
   202→  /**
   203→   * Called when animated zoom completes or is acknowledged.
   204→   */
   205→  onAnimatedZoomComplete?: () => void;
   206→}
   207→
   208→// Navigation limits
   209→const ABSOLUTE_MIN_ZOOM = 0.05; // Absolute minimum to prevent extreme zoom out
   210→const MAX_ZOOM = 5.0;
   211→
   212→// Momentum physics constants
   213→const MOMENTUM_FRICTION = 0.93; // Per-frame velocity multiplier (0.93-0.95 recommended)
   214→const MOMENTUM_MIN_VELOCITY = 0.5; // Stop threshold in world units
   215→const MOMENTUM_VELOCITY_SAMPLES = 5; // Number of velocity samples to average
   216→
   217→// Smooth zoom constants
   218→const ZOOM_ANIMATION_DURATION = 250; // ms for animated zoom transitions
   219→const ZOOM_ACCUMULATION_TIMEOUT = 50; // ms to accumulate wheel events (trackpad smoothing)
   220→const PINCH_ZOOM_SENSITIVITY = 0.01; // Sensitivity for pinch-to-zoom
   221→
   222→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
   223→
   224→/**
   225→ * Velocity sample for momentum calculation
   226→ */
   227→interface VelocitySample {
   228→  x: number;
   229→  y: number;
   230→  time: number;
   231→}
   232→
   233→/**
   234→ * Momentum state for inertial panning
   235→ */
   236→interface MomentumState {
   237→  velocityX: number;
   238→  velocityY: number;
   239→  animationId: number | null;
   240→}
   241→
   242→/**
   243→ * Zoom animation state for smooth zoom transitions
   244→ */
   245→interface ZoomAnimationState {
   246→  animationId: number | null;
   247→  startZoom: number;
   248→  targetZoom: number;
   249→  startCameraX: number;
   250→  startCameraY: number;
   251→  targetCameraX: number;
   252→  targetCameraY: number;
   253→  startTime: number;
   254→  duration: number;
   255→}
   256→
   257→/**
   258→ * Pinch-to-zoom state for touch gestures
   259→ */
   260→interface PinchState {
   261→  active: boolean;
   262→  initialDistance: number;
   263→  initialZoom: number;
   264→  centerX: number;
   265→  centerY: number;
   266→  pointers: Map<number, { x: number; y: number }>;
   267→}
   268→
   269→/**
   270→ * Easing functions for smooth animations
   271→ * quadOut provides Google Maps-style smooth deceleration
   272→ */
   273→const Easing = {
   274→  quadOut: (t: number) => t * (2 - t),
   275→  cubicOut: (t: number) => 1 - Math.pow(1 - t, 3),
   276→};
   277→
   278→/**
   279→ * Camera controller component (inside R3F context)
   280→ * Handles initial positioning and syncs camera with external state
   281→ *
   282→ * IMPORTANT: Uses R3F's `size` from useThree() which is the actual canvas size,
   283→ * not the container div size (which can differ due to flexbox/layout).
   284→ */
   285→function CameraController({
   286→  cameraX,
   287→  cameraY,
   288→  zoom,
   289→  worldBounds,
   290→  isInitialized,
   291→  onInitialized,
   292→  onViewportChange,
   293→}: {
   294→  cameraX: number;
   295→  cameraY: number;
   296→  zoom: number;
   297→  worldBounds: WorldBounds;
   298→  isInitialized: boolean;
   299→  onInitialized: (pos: { x: number; y: number }, size: { width: number; height: number }) => void;
   300→  onViewportChange?: (viewport: ViewportInfo) => void;
   301→}) {
   302→  const { camera, size } = useThree();
   303→
   304→  // Initialize camera position on first render using actual R3F size
   305→  useEffect(() => {
   306→    if (isInitialized || size.width === 0 || size.height === 0) return;
   307→
   308→    const halfViewX = size.width / 2 / zoom;
   309→    const halfViewY = size.height / 2 / zoom;
   310→
   311→    // Position camera to show top-left corner (X=0, Y=0)
   312→    const initialCameraX = halfViewX;
   313→    const initialCameraY = -halfViewY;
   314→
   315→    // Clamp to world bounds
   316→    const minCameraX = worldBounds.minX + halfViewX;
   317→    const maxCameraX = worldBounds.maxX - halfViewX;
   318→    const minCameraY = worldBounds.minY + halfViewY;
   319→    const maxCameraY = worldBounds.maxY - halfViewY;
   320→
   321→    const clampedX = Math.max(minCameraX, Math.min(maxCameraX, initialCameraX));
   322→    const clampedY = Math.max(minCameraY, Math.min(maxCameraY, initialCameraY));
   323→
   324→    // Update camera
   325→    camera.position.x = clampedX;
   326→    camera.position.y = clampedY;
   327→    (camera as any).zoom = zoom;
   328→    camera.updateProjectionMatrix();
   329→
   330→    // Notify parent of initial position and actual canvas size
   331→    onInitialized({ x: clampedX, y: clampedY }, { width: size.width, height: size.height });
   332→
   333→    // Notify viewport change with full viewport info
   334→    const topY = clampedY + halfViewY;
   335→    const leftX = clampedX - halfViewX;
   336→    const rightX = clampedX + halfViewX;
   337→    onViewportChange?.({ topY, leftX, rightX });
   338→  }, [size, zoom, worldBounds, camera, isInitialized, onInitialized, onViewportChange]);
   339→
   340→  // Sync camera with external state changes (after initialization)
   341→  useEffect(() => {
   342→    if (!isInitialized) return;
   343→
   344→    camera.position.x = cameraX;
   345→    camera.position.y = cameraY;
   346→    (camera as any).zoom = zoom;
   347→    camera.updateProjectionMatrix();
   348→  }, [camera, cameraX, cameraY, zoom, isInitialized]);
   349→
   350→  return null;
   351→}
   352→
   353→export function InfiniteCanvas({
   354→  zoom,
   355→  lod,
   356→  onZoomChange,
   357→  onViewportChange,
   358→  onMinZoomChange,
   359→  animatedZoomTarget,
   360→  onAnimatedZoomComplete,
   361→}: InfiniteCanvasProps) {
   362→  const containerRef = useRef<HTMLDivElement>(null);
   363→  const [isInitialized, setIsInitialized] = useState(false);
   364→  // Store actual canvas size from R3F (not container div)
   365→  const [canvasSize, setCanvasSize] = useState({ width: 800, height: 600 });
   366→
   367→  // Get render data (memoized)
   368→  const { trains, tasks } = useMemo(() => getRenderData(), []);
   369→
   370→  // Calculate world bounds (for pan clamping)
   371→  const worldBounds = useMemo<WorldBounds>(() => {
   372→    const totalDays = 365 * 10; // 10 years
   373→    return calculateWorldBounds(trains.length, totalDays);
   374→  }, [trains.length]);
   375→
   376→  /**
   377→   * Calculate dynamic MIN_ZOOM to prevent white space around content.
   378→   * MIN_ZOOM is set so the viewport never exceeds the world bounds.
   379→   */
   380→  const effectiveMinZoom = useMemo(() => {
   381→    if (canvasSize.width === 0 || canvasSize.height === 0) {
   382→      return ABSOLUTE_MIN_ZOOM;
   383→    }
   384→
   385→    const worldWidth = worldBounds.maxX - worldBounds.minX;
   386→    const worldHeight = Math.abs(worldBounds.maxY - worldBounds.minY);
   387→
   388→    // Calculate zoom levels where viewport equals world dimensions
   389→    // At zoom Z: viewportWidth = canvasSize.width / Z
   390→    // To fit world: canvasSize.width / Z = worldWidth → Z = canvasSize.width / worldWidth
   391→    const minZoomX = canvasSize.width / worldWidth;
   392→    const minZoomY = canvasSize.height / worldHeight;
   393→
   394→    // Use the maximum to ensure content fills viewport in both dimensions
   395→    const dynamicMin = Math.max(minZoomX, minZoomY);
   396→
   397→    // Clamp to absolute minimum (safety) and return
   398→    return Math.max(ABSOLUTE_MIN_ZOOM, dynamicMin);
   399→  }, [canvasSize.width, canvasSize.height, worldBounds]);
   400→
   401→  // Notify parent when effective min zoom changes
   402→  useEffect(() => {
   403→    onMinZoomChange?.(effectiveMinZoom);
   404→  }, [effectiveMinZoom, onMinZoomChange]);
   405→
   406→  // Camera position state
   407→  const [cameraPos, setCameraPos] = useState({ x: 0, y: 0 });
   408→
   409→  // Pan state
   410→  const [isPanning, setIsPanning] = useState(false);
   411→  const [panStart, setPanStart] = useState({ x: 0, y: 0 });
   412→  const [cameraPosAtPanStart, setCameraPosAtPanStart] = useState({ x: 0, y: 0 });
   413→
   414→  // Momentum state for inertial panning
   415→  const velocitySamplesRef = useRef<VelocitySample[]>([]);
   416→  const momentumRef = useRef<MomentumState>({
   417→    velocityX: 0,
   418→    velocityY: 0,
   419→    animationId: null,
   420→  });
   421→  const lastPointerPosRef = useRef({ x: 0, y: 0, time: 0 });
   422→
   423→  // Smooth zoom animation state
   424→  const zoomAnimationRef = useRef<ZoomAnimationState>({
   425→    animationId: null,
   426→    startZoom: 1,
   427→    targetZoom: 1,
   428→    startCameraX: 0,
   429→    startCameraY: 0,
   430→    targetCameraX: 0,
   431→    targetCameraY: 0,
   432→    startTime: 0,
   433→    duration: ZOOM_ANIMATION_DURATION,
   434→  });
   435→
   436→  // Wheel event accumulation for trackpad smooth zoom
   437→  const wheelAccumulatorRef = useRef({
   438→    delta: 0,
   439→    cursorX: 0,
   440→    cursorY: 0,
   441→    timeout: null as ReturnType<typeof setTimeout> | null,
   442→  });
   443→
   444→  // Pinch-to-zoom state
   445→  const pinchRef = useRef<PinchState>({
   446→    active: false,
   447→    initialDistance: 0,
   448→    initialZoom: 1,
   449→    centerX: 0,
   450→    centerY: 0,
   451→    pointers: new Map(),
   452→  });
   453→
   454→  /**
   455→   * Called by CameraController when it initializes with actual R3F canvas size
   456→   */
   457→  const handleCameraInitialized = useCallback(
   458→    (pos: { x: number; y: number }, size: { width: number; height: number }) => {
   459→      setCameraPos(pos);
   460→      setCanvasSize(size);
   461→      setIsInitialized(true);
   462→    },
   463→    []
   464→  );
   465→
   466→  /**
   467→   * Calculate and notify the viewport position (topY, leftX, rightX)
   468→   */
   469→  const notifyViewportChange = useCallback(
   470→    (camX: number, camY: number, currentZoom: number) => {
   471→      const halfViewX = canvasSize.width / 2 / currentZoom;
   472→      const halfViewY = canvasSize.height / 2 / currentZoom;
   473→      const topY = camY + halfViewY;
   474→      const leftX = camX - halfViewX;
   475→      const rightX = camX + halfViewX;
   476→      onViewportChange?.({ topY, leftX, rightX });
   477→    },
   478→    [canvasSize.width, canvasSize.height, onViewportChange]
   479→  );
   480→
   481→  /**
   482→   * Clamp camera position to world bounds
   483→   */
   484→  const clampCameraToWorld = useCallback(
   485→    (x: number, y: number, currentZoom: number): { x: number; y: number } => {
   486→      const halfViewX = canvasSize.width / 2 / currentZoom;
   487→      const halfViewY = canvasSize.height / 2 / currentZoom;
   488→
   489→      const minCameraX = worldBounds.minX + halfViewX;
   490→      const maxCameraX = worldBounds.maxX - halfViewX;
   491→      const minCameraY = worldBounds.minY + halfViewY;
   492→      const maxCameraY = worldBounds.maxY - halfViewY;
   493→
   494→      const clampedX =
   495→        maxCameraX < minCameraX
   496→          ? (worldBounds.minX + worldBounds.maxX) / 2
   497→          : Math.max(minCameraX, Math.min(maxCameraX, x));
   498→
   499→      const clampedY =
   500→        maxCameraY < minCameraY
   501→          ? (worldBounds.minY + worldBounds.maxY) / 2
   502→          : Math.max(minCameraY, Math.min(maxCameraY, y));
   503→
   504→      return { x: clampedX, y: clampedY };
   505→    },
   506→    [canvasSize, worldBounds]
   507→  );
   508→
   509→  /**
   510→   * Stop any active momentum animation
   511→   */
   512→  const stopMomentum = useCallback(() => {
   513→    if (momentumRef.current.animationId) {
   514→      cancelAnimationFrame(momentumRef.current.animationId);
   515→      momentumRef.current.animationId = null;
   516→    }
   517→    momentumRef.current.velocityX = 0;
   518→    momentumRef.current.velocityY = 0;
   519→    velocitySamplesRef.current = [];
   520→  }, []);
   521→
   522→  /**
   523→   * Stop any active zoom animation
   524→   */
   525→  const stopZoomAnimation = useCallback(() => {
   526→    if (zoomAnimationRef.current.animationId) {
   527→      cancelAnimationFrame(zoomAnimationRef.current.animationId);
   528→      zoomAnimationRef.current.animationId = null;
   529→    }
   530→    // Clear wheel accumulator
   531→    if (wheelAccumulatorRef.current.timeout) {
   532→      clearTimeout(wheelAccumulatorRef.current.timeout);
   533→      wheelAccumulatorRef.current.timeout = null;
   534→    }
   535→    wheelAccumulatorRef.current.delta = 0;
   536→  }, []);
   537→
   538→  /**
   539→   * Animate zoom smoothly from current to target
   540→   * Uses quadratic easing for Google Maps-like feel
   541→   */
   542→  const animateZoomTo = useCallback(
   543→    (
   544→      targetZoom: number,
   545→      targetCameraX: number,
   546→      targetCameraY: number,
   547→      duration: number = ZOOM_ANIMATION_DURATION
   548→    ) => {
   549→      // Stop any existing animation
   550→      stopZoomAnimation();
   551→
   552→      const state = zoomAnimationRef.current;
   553→      state.startZoom = zoom;
   554→      state.targetZoom = targetZoom;
   555→      state.startCameraX = cameraPos.x;
   556→      state.startCameraY = cameraPos.y;
   557→      state.targetCameraX = targetCameraX;
   558→      state.targetCameraY = targetCameraY;
   559→      state.startTime = performance.now();
   560→      state.duration = duration;
   561→
   562→      const animate = (currentTime: number) => {
   563→        const elapsed = currentTime - state.startTime;
   564→        const progress = Math.min(elapsed / state.duration, 1);
   565→        const easedProgress = Easing.quadOut(progress);
   566→
   567→        const currentZoom = state.startZoom + (state.targetZoom - state.startZoom) * easedProgress;
   568→        const currentCameraX = state.startCameraX + (state.targetCameraX - state.startCameraX) * easedProgress;
   569→        const currentCameraY = state.startCameraY + (state.targetCameraY - state.startCameraY) * easedProgress;
   570→
   571→        // Clamp camera position
   572→        const clamped = clampCameraToWorld(currentCameraX, currentCameraY, currentZoom);
   573→
   574→        setCameraPos(clamped);
   575→        onZoomChange(currentZoom);
   576→        notifyViewportChange(clamped.x, clamped.y, currentZoom);
   577→
   578→        if (progress < 1) {
   579→          state.animationId = requestAnimationFrame(animate);
   580→        } else {
   581→          state.animationId = null;
   582→        }
   583→      };
   584→
   585→      state.animationId = requestAnimationFrame(animate);
   586→    },
   587→    [zoom, cameraPos, clampCameraToWorld, onZoomChange, notifyViewportChange, stopZoomAnimation]
   588→  );
   589→
   590→  /**
   591→   * Calculate average velocity from samples
   592→   * Samples contain individual deltas (movement per event), not absolute positions
   593→   */
   594→  const calculateAverageVelocity = useCallback(() => {
   595→    const samples = velocitySamplesRef.current;
   596→    if (samples.length < 2) return { vx: 0, vy: 0 };
   597→
   598→    // Use only recent samples (last N samples)
   599→    const recentSamples = samples.slice(-MOMENTUM_VELOCITY_SAMPLES);
   600→    if (recentSamples.length < 2) return { vx: 0, vy: 0 };
   601→
   602→    // Calculate total displacement and time
   603→    const first = recentSamples[0];
   604→    const last = recentSamples[recentSamples.length - 1];
   605→    const dt = last.time - first.time;
   606→
   607→    if (dt <= 0) return { vx: 0, vy: 0 };
   608→
   609→    // Sum all deltas to get total displacement
   610→    let totalDx = 0;
   611→    let totalDy = 0;
   612→    for (const sample of recentSamples) {
   613→      totalDx += sample.x;
   614→      totalDy += sample.y;
   615→    }
   616→
   617→    // Velocity in world units per millisecond
   618→    const vx = totalDx / dt;
   619→    const vy = totalDy / dt;
   620→
   621→    return { vx, vy };
   622→  }, []);
   623→
   624→  /**
   625→   * Start momentum animation after drag release
   626→   */
   627→  const startMomentum = useCallback(
   628→    (vx: number, vy: number) => {
   629→      // Convert velocity from world/ms to world/frame (at 60fps, ~16.67ms per frame)
   630→      const frameTime = 16.67;
   631→      momentumRef.current.velocityX = vx * frameTime;
   632→      momentumRef.current.velocityY = vy * frameTime;
   633→
   634→      // Clear samples
   635→      velocitySamplesRef.current = [];
   636→
   637→      const animate = () => {
   638→        const { velocityX, velocityY } = momentumRef.current;
   639→
   640→        // Check if velocity is negligible
   641→        const speed = Math.sqrt(velocityX ** 2 + velocityY ** 2);
   642→        if (speed < MOMENTUM_MIN_VELOCITY) {
   643→          momentumRef.current.animationId = null;
   644→          return;
   645→        }
   646→
   647→        // Apply velocity to camera position
   648→        setCameraPos((prev) => {
   649→          const newX = prev.x + velocityX;
   650→          const newY = prev.y - velocityY; // Inverted for camera Y
   651→          const clamped = clampCameraToWorld(newX, newY, zoom);
   652→          notifyViewportChange(clamped.x, clamped.y, zoom);
   653→          return clamped;
   654→        });
   655→
   656→        // Apply friction
   657→        momentumRef.current.velocityX *= MOMENTUM_FRICTION;
   658→        momentumRef.current.velocityY *= MOMENTUM_FRICTION;
   659→
   660→        // Continue animation
   661→        momentumRef.current.animationId = requestAnimationFrame(animate);
   662→      };
   663→
   664→      // Start animation
   665→      momentumRef.current.animationId = requestAnimationFrame(animate);
   666→    },
   667→    [clampCameraToWorld, notifyViewportChange, zoom]
   668→  );
   669→
   670→  /**
   671→   * Calculate target camera position for zoom toward a point
   672→   */
   673→  const calculateZoomTowardPoint = useCallback(
   674→    (cursorX: number, cursorY: number, fromZoom: number, toZoom: number) => {
   675→      // Convert cursor to world coordinates (before zoom)
   676→      const worldX = cursorX / fromZoom + cameraPos.x;
   677→      const worldY = -cursorY / fromZoom + cameraPos.y;
   678→
   679→      // Calculate new camera position to keep cursor point fixed
   680→      const newCameraX = worldX - cursorX / toZoom;
   681→      const newCameraY = worldY + cursorY / toZoom;
   682→
   683→      return clampCameraToWorld(newCameraX, newCameraY, toZoom);
   684→    },
   685→    [cameraPos, clampCameraToWorld]
   686→  );
   687→
   688→  /**
   689→   * Execute accumulated zoom with smooth animation
   690→   * Called after wheel events are accumulated (for trackpad smoothing)
   691→   */
   692→  const executeAccumulatedZoom = useCallback(() => {
   693→    const accumulator = wheelAccumulatorRef.current;
   694→    if (accumulator.delta === 0) return;
   695→
   696→    const rect = containerRef.current?.getBoundingClientRect();
   697→    if (!rect) return;
   698→
   699→    // Get the current zoom (may be in animation)
   700→    const currentZoom = zoomAnimationRef.current.animationId
   701→      ? zoomAnimationRef.current.targetZoom
   702→      : zoom;
   703→
   704→    // Calculate zoom factor from accumulated delta
   705→    // Smooth factor: smaller deltas = smoother zoom
   706→    const zoomFactor = Math.pow(0.995, accumulator.delta);
   707→    const newZoom = Math.max(effectiveMinZoom, Math.min(MAX_ZOOM, currentZoom * zoomFactor));
   708→
   709→    if (Math.abs(newZoom - currentZoom) < 0.001) {
   710→      accumulator.delta = 0;
   711→      return;
   712→    }
   713→
   714→    // Cursor position relative to canvas center
   715→    const cursorX = accumulator.cursorX - rect.left - rect.width / 2;
   716→    const cursorY = accumulator.cursorY - rect.top - rect.height / 2;
   717→
   718→    // Get current camera position (may be in animation)
   719→    const currentCameraX = zoomAnimationRef.current.animationId
   720→      ? zoomAnimationRef.current.targetCameraX
   721→      : cameraPos.x;
   722→    const currentCameraY = zoomAnimationRef.current.animationId
   723→      ? zoomAnimationRef.current.targetCameraY
   724→      : cameraPos.y;
   725→
   726→    // Calculate target camera position
   727→    const worldX = cursorX / currentZoom + currentCameraX;
   728→    const worldY = -cursorY / currentZoom + currentCameraY;
   729→    const newCameraX = worldX - cursorX / newZoom;
   730→    const newCameraY = worldY + cursorY / newZoom;
   731→    const clamped = clampCameraToWorld(newCameraX, newCameraY, newZoom);
   732→
   733→    // Reset accumulator
   734→    accumulator.delta = 0;
   735→    accumulator.timeout = null;
   736→
   737→    // Animate to new zoom
   738→    animateZoomTo(newZoom, clamped.x, clamped.y, ZOOM_ANIMATION_DURATION);
   739→  }, [zoom, cameraPos, effectiveMinZoom, clampCameraToWorld, animateZoomTo]);
   740→
   741→  /**
   742→   * Handle wheel zoom - smooth zoom toward cursor position
   743→   * Accumulates wheel events for trackpad smoothing, then animates
   744→   */
   745→  const handleWheel = useCallback(
   746→    (e: WheelEvent) => {
   747→      e.preventDefault();
   748→      if (!isInitialized) return;
   749→
   750→      // Stop momentum on any zoom interaction
   751→      stopMomentum();
   752→
   753→      const rect = containerRef.current?.getBoundingClientRect();
   754→      if (!rect) return;
   755→
   756→      const accumulator = wheelAccumulatorRef.current;
   757→
   758→      // Accumulate delta (positive = zoom out, negative = zoom in)
   759→      accumulator.delta += e.deltaY;
   760→      accumulator.cursorX = e.clientX;
   761→      accumulator.cursorY = e.clientY;
   762→
   763→      // Clear existing timeout
   764→      if (accumulator.timeout) {
   765→        clearTimeout(accumulator.timeout);
   766→      }
   767→
   768→      // Set timeout to execute accumulated zoom
   769→      // This groups rapid wheel events (trackpad) into single smooth animation
   770→      accumulator.timeout = setTimeout(() => {
   771→        executeAccumulatedZoom();
   772→      }, ZOOM_ACCUMULATION_TIMEOUT);
   773→    },
   774→    [isInitialized, stopMomentum, executeAccumulatedZoom]
   775→  );
   776→
   777→  /**
   778→   * Handle pinch-to-zoom for touch devices
   779→   */
   780→  const handlePinchZoom = useCallback(
   781→    (scale: number, centerX: number, centerY: number) => {
   782→      const pinch = pinchRef.current;
   783→      const newZoom = Math.max(effectiveMinZoom, Math.min(MAX_ZOOM, pinch.initialZoom * scale));
   784→
   785→      const rect = containerRef.current?.getBoundingClientRect();
   786→      if (!rect) return;
   787→
   788→      // Center position relative to canvas center
   789→      const cursorX = centerX - rect.left - rect.width / 2;
   790→      const cursorY = centerY - rect.top - rect.height / 2;
   791→
   792→      // Calculate camera position to keep pinch center fixed
   793→      const worldX = cursorX / pinch.initialZoom + pinch.centerX;
   794→      const worldY = -cursorY / pinch.initialZoom + pinch.centerY;
   795→      const newCameraX = worldX - cursorX / newZoom;
   796→      const newCameraY = worldY + cursorY / newZoom;
   797→
   798→      const clamped = clampCameraToWorld(newCameraX, newCameraY, newZoom);
   799→
   800→      setCameraPos(clamped);
   801→      onZoomChange(newZoom);
   802→      notifyViewportChange(clamped.x, clamped.y, newZoom);
   803→    },
   804→    [effectiveMinZoom, clampCameraToWorld, onZoomChange, notifyViewportChange]
   805→  );
   806→
   807→  // Register wheel event with { passive: false } to allow preventDefault
   808→  useEffect(() => {
   809→    const container = containerRef.current;
   810→    if (!container) return;
   811→
   812→    container.addEventListener('wheel', handleWheel, { passive: false });
   813→    return () => container.removeEventListener('wheel', handleWheel);
   814→  }, [handleWheel]);
   815→
   816→  // Cleanup animations on unmount
   817→  useEffect(() => {
   818→    return () => {
   819→      if (momentumRef.current.animationId) {
   820→        cancelAnimationFrame(momentumRef.current.animationId);
   821→      }
   822→      if (zoomAnimationRef.current.animationId) {
   823→        cancelAnimationFrame(zoomAnimationRef.current.animationId);
   824→      }
   825→      if (wheelAccumulatorRef.current.timeout) {
   826→        clearTimeout(wheelAccumulatorRef.current.timeout);
   827→      }
   828→    };
   829→  }, []);
   830→
   831→  // Handle animated zoom requests from parent (button +/-)
   832→  useEffect(() => {
   833→    if (animatedZoomTarget == null || !isInitialized) return;
   834→
   835→    // Calculate new camera position (zoom toward center of viewport)
   836→    const targetZoom = Math.max(effectiveMinZoom, Math.min(MAX_ZOOM, animatedZoomTarget));
   837→    if (Math.abs(targetZoom - zoom) < 0.001) {
   838→      onAnimatedZoomComplete?.();
   839→      return;
   840→    }
   841→
   842→    // Zoom toward center (no cursor offset)
   843→    const clamped = clampCameraToWorld(cameraPos.x, cameraPos.y, targetZoom);
   844→    animateZoomTo(targetZoom, clamped.x, clamped.y, ZOOM_ANIMATION_DURATION);
   845→
   846→    // Acknowledge the request
   847→    onAnimatedZoomComplete?.();
   848→  }, [animatedZoomTarget, isInitialized, zoom, effectiveMinZoom, cameraPos, clampCameraToWorld, animateZoomTo, onAnimatedZoomComplete]);
   849→
   850→  /**
   851→   * Handle pan start / pinch start
   852→   */
   853→  const handlePointerDown = useCallback(
   854→    (e: React.PointerEvent) => {
   855→      if (!isInitialized) return;
   856→
   857→      const pinch = pinchRef.current;
   858→
   859→      // Track pointer for pinch detection
   860→      pinch.pointers.set(e.pointerId, { x: e.clientX, y: e.clientY });
   861→
   862→      // Check for pinch gesture (2 pointers)
   863→      if (pinch.pointers.size === 2) {
   864→        // Stop pan and momentum when pinch starts
   865→        stopMomentum();
   866→        stopZoomAnimation();
   867→        setIsPanning(false);
   868→
   869→        const pointers = Array.from(pinch.pointers.values());
   870→        const dx = pointers[0].x - pointers[1].x;
   871→        const dy = pointers[0].y - pointers[1].y;
   872→        pinch.initialDistance = Math.sqrt(dx * dx + dy * dy);
   873→        pinch.initialZoom = zoom;
   874→        pinch.centerX = cameraPos.x;
   875→        pinch.centerY = cameraPos.y;
   876→        pinch.active = true;
   877→        return;
   878→      }
   879→
   880→      // Single pointer = pan
   881→      if (pinch.pointers.size === 1) {
   882→        // Stop any active momentum and zoom animation
   883→        stopMomentum();
   884→        stopZoomAnimation();
   885→
   886→        setIsPanning(true);
   887→        setPanStart({ x: e.clientX, y: e.clientY });
   888→        setCameraPosAtPanStart(cameraPos);
   889→
   890→        // Initialize velocity tracking
   891→        const now = performance.now();
   892→        lastPointerPosRef.current = { x: e.clientX, y: e.clientY, time: now };
