   897→    },
   898→    [cameraPos, zoom, isInitialized, stopMomentum, stopZoomAnimation]
   899→  );
   900→
   901→  /**
   902→   * Handle pan move / pinch move
   903→   */
   904→  const handlePointerMove = useCallback(
   905→    (e: React.PointerEvent) => {
   906→      const pinch = pinchRef.current;
   907→
   908→      // Update pointer position
   909→      if (pinch.pointers.has(e.pointerId)) {
   910→        pinch.pointers.set(e.pointerId, { x: e.clientX, y: e.clientY });
   911→      }
   912→
   913→      // Handle pinch gesture
   914→      if (pinch.active && pinch.pointers.size === 2) {
   915→        const pointers = Array.from(pinch.pointers.values());
   916→        const dx = pointers[0].x - pointers[1].x;
   917→        const dy = pointers[0].y - pointers[1].y;
   918→        const currentDistance = Math.sqrt(dx * dx + dy * dy);
