   943→      // Track velocity samples for momentum
   944→      const now = performance.now();
   945→      const worldDx = (e.clientX - lastPointerPosRef.current.x) / zoom;
   946→      const worldDy = (e.clientY - lastPointerPosRef.current.y) / zoom;
