   955→      if (velocitySamplesRef.current.length > MOMENTUM_VELOCITY_SAMPLES * 2) {
   956→        velocitySamplesRef.current = velocitySamplesRef.current.slice(-MOMENTUM_VELOCITY_SAMPLES);
