   958→
   959→      lastPointerPosRef.current = { x: e.clientX, y: e.clientY, time: now };
   960→    },
   961→    [isPanning, panStart, cameraPosAtPanStart, zoom, clampCameraToWorld, notifyViewportChange, handlePinchZoom]
   962→  );
   963→
   964→  /**
   965→   * Handle pan end / pinch end
   966→   */
   967→  const handlePointerUp = useCallback(
   968→    (e: React.PointerEvent) => {
   969→      const pinch = pinchRef.current;
   970→
