   987→      // Handle pan end with momentum
   988→      if (isPanning && pinch.pointers.size === 0) {
   989→        setIsPanning(false);
   990→
   991→        // Calculate and start momentum
   992→        const { vx, vy } = calculateAverageVelocity();
   993→
   994→        // Only start momentum if velocity is significant
   995→        const speed = Math.sqrt(vx ** 2 + vy ** 2);
   996→        if (speed > 0.01) {
   997→          // Threshold: 0.01 world units per ms
   998→          startMomentum(vx, vy);
   999→        }
  1000→      }
  1001→    },
  1002→    [isPanning, calculateAverageVelocity, startMomentum]
  1003→  );
  1004→
  1005→  /**
  1006→   * Handle double-click to zoom in at click location
  1007→   * Zooms 2x toward the clicked point with smooth animation
  1008→   */
  1009→  const handleDoubleClick = useCallback(
  1010→    (e: React.MouseEvent) => {
  1011→      if (!isInitialized) return;
  1012→
  1013→      // Stop any active animations
  1014→      stopMomentum();
  1015→      stopZoomAnimation();
  1016→
  1017→      const rect = containerRef.current?.getBoundingClientRect();
  1018→      if (!rect) return;
  1019→
  1020→      // Calculate target zoom (2x, clamped to MAX_ZOOM)
  1021→      const targetZoom = Math.min(zoom * 2, MAX_ZOOM);
  1022→      if (Math.abs(targetZoom - zoom) < 0.001) return;
  1023→
  1024→      // Cursor position relative to canvas center
  1025→      const cursorX = e.clientX - rect.left - rect.width / 2;
  1026→      const cursorY = e.clientY - rect.top - rect.height / 2;
  1027→
  1028→      // Calculate target camera position (zoom toward click point)
  1029→      const worldX = cursorX / zoom + cameraPos.x;
  1030→      const worldY = -cursorY / zoom + cameraPos.y;
  1031→      const newCameraX = worldX - cursorX / targetZoom;
  1032→      const newCameraY = worldY + cursorY / targetZoom;
  1033→
  1034→      const clamped = clampCameraToWorld(newCameraX, newCameraY, targetZoom);
  1035→
  1036→      // Animate with slightly longer duration for double-click (350ms, cubicOut)
  1037→      const state = zoomAnimationRef.current;
  1038→      stopZoomAnimation();
  1039→
  1040→      state.startZoom = zoom;
  1041→      state.targetZoom = targetZoom;
  1042→      state.startCameraX = cameraPos.x;
  1043→      state.startCameraY = cameraPos.y;
  1044→      state.targetCameraX = clamped.x;
  1045→      state.targetCameraY = clamped.y;
  1046→      state.startTime = performance.now();
  1047→      state.duration = 350; // Longer duration for double-click
  1048→
  1049→      const animate = (currentTime: number) => {
  1050→        const elapsed = currentTime - state.startTime;
  1051→        const progress = Math.min(elapsed / state.duration, 1);
  1052→        const easedProgress = Easing.cubicOut(progress); // Use cubicOut for double-click
  1053→
  1054→        const currentZoom = state.startZoom + (state.targetZoom - state.startZoom) * easedProgress;
  1055→        const currentCameraX = state.startCameraX + (state.targetCameraX - state.startCameraX) * easedProgress;
  1056→        const currentCameraY = state.startCameraY + (state.targetCameraY - state.startCameraY) * easedProgress;
  1057→
  1058→        const clampedPos = clampCameraToWorld(currentCameraX, currentCameraY, currentZoom);
  1059→
  1060→        setCameraPos(clampedPos);
  1061→        onZoomChange(currentZoom);
  1062→        notifyViewportChange(clampedPos.x, clampedPos.y, currentZoom);
  1063→
  1064→        if (progress < 1) {
  1065→          state.animationId = requestAnimationFrame(animate);
  1066→        } else {
  1067→          state.animationId = null;
  1068→        }
  1069→      };
  1070→
  1071→      state.animationId = requestAnimationFrame(animate);
  1072→    },
  1073→    [zoom, cameraPos, isInitialized, stopMomentum, stopZoomAnimation, clampCameraToWorld, onZoomChange, notifyViewportChange]
  1074→  );
  1075→
  1076→  /**
  1077→   * Calculate viewport bounds for frustum culling
  1078→   * This determines which tasks are visible and need to be rendered
  1079→   */
  1080→  const viewportBounds = useMemo<ViewportBounds>(() => {
  1081→    const halfViewX = canvasSize.width / 2 / zoom;
  1082→    const halfViewY = canvasSize.height / 2 / zoom;
  1083→
  1084→    return {
  1085→      minX: cameraPos.x - halfViewX,
  1086→      maxX: cameraPos.x + halfViewX,
  1087→      minY: cameraPos.y - halfViewY,
  1088→      maxY: cameraPos.y + halfViewY,
  1089→    };
  1090→  }, [cameraPos.x, cameraPos.y, canvasSize.width, canvasSize.height, zoom]);
  1091→
  1092→  return (
  1093→    <div
  1094→      ref={containerRef}
  1095→      style={{
  1096→        width: '100%',
  1097→        height: '100%',
  1098→        cursor: isPanning ? 'grabbing' : 'grab',
  1099→        touchAction: 'none',
  1100→      }}
  1101→      onPointerDown={handlePointerDown}
  1102→      onPointerMove={handlePointerMove}
  1103→      onPointerUp={handlePointerUp}
  1104→      onPointerLeave={handlePointerUp}
  1105→      onDoubleClick={handleDoubleClick}
  1106→    >
  1107→      <Canvas
  1108→        gl={{ antialias: true, alpha: false }}
  1109→        style={{ background: '#f4f4f5' }}
  1110→        orthographic
  1111→        camera={{
  1112→          position: [cameraPos.x, cameraPos.y, 100],
  1113→          zoom: zoom,
  1114→          near: 0.1,
  1115→          far: 1000,
  1116→        }}
  1117→      >
  1118→        <CameraController
  1119→          cameraX={cameraPos.x}
  1120→          cameraY={cameraPos.y}
  1121→          zoom={zoom}
  1122→          worldBounds={worldBounds}
  1123→          isInitialized={isInitialized}
  1124→          onInitialized={handleCameraInitialized}
  1125→          onViewportChange={onViewportChange}
  1126→        />
  1127→
  1128→        <color attach="background" args={['#f4f4f5']} />
  1129→
  1130→        {/* LOD-based layer rendering with smooth transitions */}
  1131→        <LODLayers
  1132→          tasks={tasks}
  1133→          trainCount={trains.length}
  1134→          zoom={zoom}
  1135→          viewportBounds={viewportBounds}
  1136→        />
  1137→      </Canvas>
  1138→    </div>
  1139→  );
  1140→}
