     1→/**
     2→ * InfiniteCanvas - Professional-grade pan/zoom canvas
     3→ *
     4→ * Features:
     5→ * - Pan with mouse drag (bounded to world limits)
     6→ * - Zoom with scroll wheel (centers on cursor position)
     7→ * - Initial view shows top-left of data (X=0, Y=0)
     8→ * - Sidebar sync via onViewportChange callback
     9→ *
    10→ * Coordinate System:
    11→ * - X: 0 = first day, positive = future (right)
    12→ * - Y: 0 = first train (TRAIN-001), negative = more trains (down)
    13→ *
    14→ * References:
    15→ * - D3.js zoom: https://d3js.org/d3-zoom
    16→ * - Three.js OrthographicCamera: https://threejs.org/docs/api/en/cameras/OrthographicCamera.html
    17→ * - pixi-viewport: https://github.com/pixijs-userland/pixi-viewport
    18→ */
    19→
    20→import { Canvas, useThree } from '@react-three/fiber';
    21→import { useState, useCallback, useMemo, useEffect, useRef } from 'react';
    22→import { MesoLayer } from './layers/MesoLayer';
    23→import { MacroLayer } from './layers/MacroLayer';
    24→import { MicroLayer } from './layers/MicroLayer';
    25→import { getRenderData } from '../data/generator';
    26→import type { LODLevel, WorldBounds } from '../data/types';
    27→import { DEFAULT_VIEW_CONFIG, calculateWorldBounds } from '../data/types';
    28→
    29→// ─────────────────────────────────────────────────────────────
    30→// EXPORTED TYPES
    31→// ─────────────────────────────────────────────────────────────
    32→
    33→/**
    34→ * Viewport information passed to parent component
    35→ */
    36→export interface ViewportInfo {
    37→  /** Y coordinate of the TOP of the viewport in world space */
    38→  topY: number;
    39→  /** Left edge of the viewport in world X coordinates */
    40→  leftX: number;
    41→  /** Right edge of the viewport in world X coordinates */
    42→  rightX: number;
    43→}
    44→
    45→/**
    46→ * Viewport bounds in world coordinates
    47→ * Used for frustum culling - only render tasks within these bounds
    48→ */
    49→export interface ViewportBounds {
    50→  minX: number;
    51→  maxX: number;
    52→  minY: number;
    53→  maxY: number;
    54→}
    55→
    56→// ─────────────────────────────────────────────────────────────
    57→// LOD CONFIGURATION
    58→// ─────────────────────────────────────────────────────────────
    59→
    60→/**
    61→ * LOD Transition Configuration
    62→ *
    63→ * Defines blend zones around LOD thresholds for smooth transitions.
    64→ * During blend zones, both adjacent layers render with interpolated opacity.
    65→ */
    66→const LOD_THRESHOLDS = {
    67→  macroToMeso: 0.5,  // Below 0.5 = MACRO
    68→  mesoToMicro: 2.0,  // Above 2.0 = MICRO
    69→};
    70→
    71→// Size of blend zone around each threshold (±this value)
    72→const BLEND_ZONE_SIZE = 0.15;
    73→
    74→/**
    75→ * Calculate layer opacities for smooth LOD transitions
    76→ *
    77→ * Returns opacity values for each layer (0-1).
    78→ * During blend zones, adjacent layers overlap with interpolated opacity.
    79→ */
    80→function calculateLayerOpacities(zoom: number): {
    81→  macro: number;
    82→  meso: number;
    83→  micro: number;
    84→} {
    85→  const { macroToMeso, mesoToMicro } = LOD_THRESHOLDS;
    86→
    87→  // Define blend zone boundaries
    88→  const macroEnd = macroToMeso - BLEND_ZONE_SIZE; // 0.35
    89→  const mesoStart = macroToMeso + BLEND_ZONE_SIZE; // 0.65
    90→  const mesoEnd = mesoToMicro - BLEND_ZONE_SIZE; // 1.85
    91→  const microStart = mesoToMicro + BLEND_ZONE_SIZE; // 2.15
    92→
    93→  let macro = 0;
    94→  let meso = 0;
    95→  let micro = 0;
    96→
    97→  // Calculate MACRO opacity
    98→  if (zoom <= macroEnd) {
    99→    macro = 1;
   100→  } else if (zoom < mesoStart) {
   101→    // Blend zone MACRO → MESO
   102→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   103→    macro = 1 - t;
   104→  }
   105→
   106→  // Calculate MESO opacity
   107→  if (zoom < macroEnd) {
   108→    meso = 0;
   109→  } else if (zoom < mesoStart) {
   110→    // Blend zone MACRO → MESO
   111→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   112→    meso = t;
   113→  } else if (zoom <= mesoEnd) {
   114→    meso = 1;
   115→  } else if (zoom < microStart) {
   116→    // Blend zone MESO → MICRO
   117→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
   118→    meso = 1 - t;
   119→  }
   120→
   121→  // Calculate MICRO opacity
   122→  if (zoom <= mesoEnd) {
   123→    micro = 0;
   124→  } else if (zoom < microStart) {
   125→    // Blend zone MESO → MICRO
   126→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
   127→    micro = t;
   128→  } else {
   129→    micro = 1;
   130→  }
   131→
   132→  return { macro, meso, micro };
   133→}
   134→
   135→/**
   136→ * LODLayers - Orchestrates layer rendering with smooth transitions
   137→ *
   138→ * Renders multiple layers simultaneously during blend zones,
   139→ * with opacity interpolation for smooth visual transitions.
   140→ */
   141→function LODLayers({
   142→  tasks,
   143→  trainCount,
   144→  zoom,
   145→  viewportBounds,
   146→}: {
   147→  tasks: ReturnType<typeof getRenderData>['tasks'];
   148→  trainCount: number;
   149→  zoom: number;
   150→  viewportBounds: ViewportBounds;
   151→}) {
   152→  const opacities = useMemo(() => calculateLayerOpacities(zoom), [zoom]);
   153→
   154→  return (
   155→    <group>
   156→      {/* Render each layer if opacity > 0 */}
   157→      {opacities.macro > 0 && (
   158→        <MacroLayer
   159→          tasks={tasks}
   160→          trainCount={trainCount}
   161→          opacity={opacities.macro}
   162→        />
   163→      )}
   164→      {opacities.meso > 0 && (
   165→        <MesoLayer
   166→          tasks={tasks}
   167→          trainCount={trainCount}
   168→          opacity={opacities.meso}
   169→        />
   170→      )}
   171→      {opacities.micro > 0 && (
   172→        <MicroLayer
   173→          tasks={tasks}
   174→          trainCount={trainCount}
   175→          opacity={opacities.micro}
   176→          viewportBounds={viewportBounds}
   177→        />
   178→      )}
   179→    </group>
   180→  );
   181→}
   182→
   183→interface InfiniteCanvasProps {
   184→  zoom: number;
   185→  lod: LODLevel;
   186→  onZoomChange: (zoom: number) => void;
   187→  /**
   188→   * Called when viewport position changes.
   189→   * @param viewport - Object with topY, leftX, rightX coordinates
   190→   */
   191→  onViewportChange?: (viewport: ViewportInfo) => void;
   192→  /**
   193→   * Called when the effective minimum zoom changes.
   194→   * Used by parent to enforce zoom limits on buttons.
   195→   */
   196→  onMinZoomChange?: (minZoom: number) => void;
   197→  /**
   198→   * Request a smooth animated zoom to target level.
   199→   * Called by parent buttons for +/- zoom with animation.
   200→   */
   201→  animatedZoomTarget?: number | null;
   202→  /**
   203→   * Called when animated zoom completes or is acknowledged.
   204→   */
   205→  onAnimatedZoomComplete?: () => void;
   206→}
   207→
   208→// Navigation limits
   209→const ABSOLUTE_MIN_ZOOM = 0.05; // Absolute minimum to prevent extreme zoom out
   210→const MAX_ZOOM = 5.0;
   211→
   212→// Momentum physics constants
   213→const MOMENTUM_FRICTION = 0.93; // Per-frame velocity multiplier (0.93-0.95 recommended)
   214→const MOMENTUM_MIN_VELOCITY = 0.5; // Stop threshold in world units
   215→const MOMENTUM_VELOCITY_SAMPLES = 5; // Number of velocity samples to average
   216→
   217→// Smooth zoom constants
   218→const ZOOM_ANIMATION_DURATION = 250; // ms for animated zoom transitions
   219→const ZOOM_ACCUMULATION_TIMEOUT = 50; // ms to accumulate wheel events (trackpad smoothing)
   220→const PINCH_ZOOM_SENSITIVITY = 0.01; // Sensitivity for pinch-to-zoom
   221→
   222→// Cross-platform scroll normalization constants (F121)
   223→// Based on Facebook's normalizeWheel pattern and UX_RESEARCH.md
   224→const LINE_HEIGHT = 40; // Pixels per line (for deltaMode === 1)
   225→const PAGE_HEIGHT = 800; // Pixels per page (for deltaMode === 2)
   226→const MOUSE_ZOOM_SENSITIVITY = 0.003; // Base zoom sensitivity for mouse wheel
   227→const TRACKPAD_ZOOM_SENSITIVITY = 0.001; // Lower sensitivity for trackpad (many small events)
   228→const MAX_ZOOM_DELTA_PER_EVENT = 0.5; // Cap zoom change per event to prevent jumps
   229→const TRACKPAD_DETECTION_THRESHOLD = 20; // ms - events faster than this are trackpad
   230→const TRACKPAD_EVENT_COUNT_THRESHOLD = 3; // Number of rapid events to confirm trackpad
   231→
   232→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
   233→
   234→/**
   235→ * Velocity sample for momentum calculation
   236→ */
   237→interface VelocitySample {
   238→  x: number;
   239→  y: number;
   240→  time: number;
   241→}
   242→
   243→/**
   244→ * Momentum state for inertial panning
   245→ */
   246→interface MomentumState {
   247→  velocityX: number;
   248→  velocityY: number;
   249→  animationId: number | null;
   250→}
   251→
   252→/**
   253→ * Zoom animation state for smooth zoom transitions
   254→ */
   255→interface ZoomAnimationState {
   256→  animationId: number | null;
   257→  startZoom: number;
   258→  targetZoom: number;
   259→  startCameraX: number;
   260→  startCameraY: number;
   261→  targetCameraX: number;
   262→  targetCameraY: number;
   263→  startTime: number;
   264→  duration: number;
   265→}
   266→
   267→/**
   268→ * Pinch-to-zoom state for touch gestures
   269→ */
   270→interface PinchState {
   271→  active: boolean;
   272→  initialDistance: number;
   273→  initialZoom: number;
   274→  centerX: number;
   275→  centerY: number;
   276→  pointers: Map<number, { x: number; y: number }>;
   277→}
   278→
   279→/**
   280→ * Easing functions for smooth animations
   281→ * quadOut provides Google Maps-style smooth deceleration
   282→ */
   283→const Easing = {
   284→  quadOut: (t: number) => t * (2 - t),
   285→  cubicOut: (t: number) => 1 - Math.pow(1 - t, 3),
   286→};
   287→
   288→/**
   289→ * Camera controller component (inside R3F context)
   290→ * Handles initial positioning and syncs camera with external state
   291→ *
   292→ * IMPORTANT: Uses R3F's `size` from useThree() which is the actual canvas size,
   293→ * not the container div size (which can differ due to flexbox/layout).
   294→ */
   295→function CameraController({
   296→  cameraX,
   297→  cameraY,
   298→  zoom,
   299→  worldBounds,
   300→  isInitialized,
   301→  onInitialized,
   302→  onViewportChange,
   303→}: {
   304→  cameraX: number;
   305→  cameraY: number;
   306→  zoom: number;
   307→  worldBounds: WorldBounds;
   308→  isInitialized: boolean;
   309→  onInitialized: (pos: { x: number; y: number }, size: { width: number; height: number }) => void;
   310→  onViewportChange?: (viewport: ViewportInfo) => void;
   311→}) {
   312→  const { camera, size } = useThree();
   313→
   314→  // Initialize camera position on first render using actual R3F size
   315→  useEffect(() => {
   316→    if (isInitialized || size.width === 0 || size.height === 0) return;
   317→
   318→    const halfViewX = size.width / 2 / zoom;
   319→    const halfViewY = size.height / 2 / zoom;
   320→
   321→    // Position camera to show top-left corner (X=0, Y=0)
   322→    const initialCameraX = halfViewX;
   323→    const initialCameraY = -halfViewY;
   324→
   325→    // Clamp to world bounds
   326→    const minCameraX = worldBounds.minX + halfViewX;
   327→    const maxCameraX = worldBounds.maxX - halfViewX;
   328→    const minCameraY = worldBounds.minY + halfViewY;
   329→    const maxCameraY = worldBounds.maxY - halfViewY;
   330→
   331→    const clampedX = Math.max(minCameraX, Math.min(maxCameraX, initialCameraX));
   332→    const clampedY = Math.max(minCameraY, Math.min(maxCameraY, initialCameraY));
   333→
   334→    // Update camera
   335→    camera.position.x = clampedX;
   336→    camera.position.y = clampedY;
   337→    (camera as any).zoom = zoom;
   338→    camera.updateProjectionMatrix();
   339→
   340→    // Notify parent of initial position and actual canvas size
   341→    onInitialized({ x: clampedX, y: clampedY }, { width: size.width, height: size.height });
   342→
   343→    // Notify viewport change with full viewport info
   344→    const topY = clampedY + halfViewY;
   345→    const leftX = clampedX - halfViewX;
   346→    const rightX = clampedX + halfViewX;
   347→    onViewportChange?.({ topY, leftX, rightX });
   348→  }, [size, zoom, worldBounds, camera, isInitialized, onInitialized, onViewportChange]);
   349→
   350→  // Sync camera with external state changes (after initialization)
   351→  useEffect(() => {
   352→    if (!isInitialized) return;
   353→
   354→    camera.position.x = cameraX;
   355→    camera.position.y = cameraY;
   356→    (camera as any).zoom = zoom;
   357→    camera.updateProjectionMatrix();
   358→  }, [camera, cameraX, cameraY, zoom, isInitialized]);
   359→
   360→  return null;
   361→}
   362→
   363→export function InfiniteCanvas({
   364→  zoom,
   365→  lod,
   366→  onZoomChange,
   367→  onViewportChange,
   368→  onMinZoomChange,
   369→  animatedZoomTarget,
   370→  onAnimatedZoomComplete,
   371→}: InfiniteCanvasProps) {
   372→  const containerRef = useRef<HTMLDivElement>(null);
   373→  const [isInitialized, setIsInitialized] = useState(false);
   374→  // Store actual canvas size from R3F (not container div)
   375→  const [canvasSize, setCanvasSize] = useState({ width: 800, height: 600 });
   376→
   377→  // Get render data (memoized)
   378→  const { trains, tasks } = useMemo(() => getRenderData(), []);
   379→
   380→  // Calculate world bounds (for pan clamping)
   381→  const worldBounds = useMemo<WorldBounds>(() => {
   382→    const totalDays = 365 * 10; // 10 years
   383→    return calculateWorldBounds(trains.length, totalDays);
   384→  }, [trains.length]);
   385→
   386→  /**
   387→   * Calculate dynamic MIN_ZOOM to prevent white space around content.
   388→   * MIN_ZOOM is set so the viewport never exceeds the world bounds.
   389→   */
   390→  const effectiveMinZoom = useMemo(() => {
   391→    if (canvasSize.width === 0 || canvasSize.height === 0) {
   392→      return ABSOLUTE_MIN_ZOOM;
   393→    }
   394→
   395→    const worldWidth = worldBounds.maxX - worldBounds.minX;
   396→    const worldHeight = Math.abs(worldBounds.maxY - worldBounds.minY);
   397→
   398→    // Calculate zoom levels where viewport equals world dimensions
