    animateZoomTo(newZoom, clamped.x, clamped.y, ZOOM_ANIMATION_DURATION);
  }, [zoom, cameraPos, effectiveMinZoom, clampCameraToWorld, animateZoomTo]);

  /**
   * Normalize wheel delta for cross-platform consistency (F121)
   * Handles deltaMode (LINE/PAGE), detects trackpad vs mouse
   * Returns normalized pixel delta
   */
  const normalizeWheelDelta = useCallback((e: WheelEvent): number => {
    let delta = e.deltaY;

