async (page) => {
  // Get the canvas element
  const canvas = await page.locator('canvas').first();
  const box = await canvas.boundingBox();

  if (!box) return 'Canvas not found';

  const centerX = box.x + box.width / 2;
  const centerY = box.y + box.height / 2;

  // Step 1: Do a quick drag to trigger momentum
  await page.mouse.move(centerX, centerY);
  await page.mouse.down();
  await page.mouse.move(centerX + 150, centerY + 100, { steps: 5 });
  await page.mouse.up();

  // Step 2: Wait a tiny bit (momentum should be running)
  await page.waitForTimeout(100);

  // Step 3: Quickly start a new drag (this is where the elastic bug would occur)
  await page.mouse.move(centerX + 150, centerY + 100);
  await page.mouse.down();
  await page.mouse.move(centerX + 200, centerY + 150, { steps: 3 });
  await page.mouse.up();

  return 'Drag test completed';
}

