    28→  SliceContext,
    29→  SliceKind,
    30→  SliceReducer,
    31→  StringTypes,
    32→} from './models';
    33→
    34→export namespace Slices {
    35→  export type SliceMapReducer = MachineReducer & { info: MachineSliceInfo };
    36→  // prettier-ignore
    37→  export type SliceMap = {
    38→    reducer: SliceMapReducer;
    39→    actionCreatorByType: { [K in StringTypes.ActionType]: RuntimeActionCreator };
    40→    actionCreatorListBySliceKey: { [K in StringTypes.SliceKey]: RuntimeActionCreator[] };
    41→    actionCreatorsSliceKey: { [K in StringTypes.SliceKey]: { [K: string]: RuntimeActionCreator } };
    42→    actionTypesBySliceKey: { [K in StringTypes.SliceKey]: { [K: string]: string } };
    43→    reducerBySliceKey: { [K: StringTypes.SliceKey]: SliceMapReducer };
    44→    reducerByActionType: { [K in StringTypes.ActionType]: SliceMapReducer };
    45→    actionTypeList: StringTypes.ActionType[];
    46→  };
    47→
    48→  /** Explicit type for sync slice model */
    49→  export type SyncSliceModel = {
    50→    id: string;
    51→    kind: SliceKind.sync;
    52→    initial: unknown;
    53→    reducers: Record<string, SliceReducer>;
    54→    cache: CacheStrategy;
    55→  };
    56→
    57→  /** Explicit type for async slice model */
    58→  export type AsyncSliceModel = {
    59→    id: string;
    60→    kind: SliceKind.async;
    61→    initial: AsyncSliceState<unknown>;
    62→    load: (...args: any[]) => Promise<unknown>;
    63→    context: SliceContext;
    64→    cache: CacheStrategy;
    65→  };
    66→
    67→  export type SlicesMap = Omit<SliceMap, 'reducer'> & {
    68→    info: MachineSliceInfo[];
    69→    mergedSlicesInitialContext: SliceContext;
    70→    mergedSlicesInitialState: AnyRecord;
    71→  };
    72→
    73→  export const SyncSliceModel = createModel({
    74→    id: 'string',
    75→    kind: { enum: [SliceKind.sync] },
    76→    initial: 'unknown',
    77→    reducers: { record: 'function' },
    78→    cache: Cache.Model,
    79→  });
    80→
    81→  export const AsyncSliceModel = createModel({
    82→    id: 'string',
    83→    kind: { enum: [SliceKind.async] },
    84→    initial: 'any',
    85→    load: 'function',
    86→    context: 'object',
    87→    cache: Cache.Model,
    88→  });
    89→
    90→  export const AnySliceModel = createType({
    91→    union: [
    92→      SyncSliceModel,
    93→      AsyncSliceModel,
    94→    ],
    95→  });
    96→
    97→  export function IsSyncSliceKind(value: unknown): value is SyncSliceModel {
    98→    assertObject(value);
    99→    return SyncSliceModel.isValid(value);
   100→  }
   101→
   102→  export function IsAsyncSliceKind(value: unknown): value is AsyncSliceModel {
   103→    assertObject(value);
   104→    return AsyncSliceModel.isValid(value);
   105→  }
   106→
   107→  export const AsyncReducerNames = new Set([
   108→    'load',
   109→    'success',
   110→    'fail',
   111→    'clear',
   112→  ] as const);
   113→
   114→  /**
   115→   * Maps one slice to internal machine utils
   116→   * @param machineID
   117→   * @param map
   118→   * @constructor
   119→   */
   120→  export function MapSlice(machineID: string, map: MachineSliceInfo): SliceMap {
   121→    const { sliceKey, slice, actionPrefix } = map;
   122→    let reducer = null as SliceMapReducer | null;
   123→    const actionCreatorByType = {} as SlicesMap['actionCreatorByType'];
   124→    const reducerByActionType = {} as SlicesMap['reducerByActionType'];
   125→    // prettier-ignore
   126→    const actionCreatorListBySliceKey = {} as SlicesMap['actionCreatorListBySliceKey'];
   127→    const actionCreatorsSliceKey = {} as SlicesMap['actionCreatorsSliceKey'];
   128→    const actionTypesBySliceKey = {} as SlicesMap['actionTypesBySliceKey'];
   129→    const actionTypeList = [] as SlicesMap['actionTypeList'];
   130→
   131→    const namePrefix = `${machineID}${capitalize(sliceKey)}`;
   132→
   133→    function registerAction(
   134→      reducerName: StringTypes.SliceReducerName,
   135→    ): RuntimeActionCreator {
   136→      const actionType =
   137→        `${actionPrefix}${reducerName}` as StringTypes.ActionType;
   138→
   139→      function action(payload: unknown): MachineAction {
   140→        return {
   141→          type: actionType,
   142→          payload,
   143→        };
   144→      }
   145→
   146→      defineFunctionName(
   147→        action,
   148→        `${namePrefix}${capitalize(reducerName)}RuntimeActionCreator`,
   149→      );
   150→      action.info = map;
   151→      action.type = actionType;
   152→      action.sliceReducerName = reducerName;
   153→      actionCreatorByType[actionType] = action;
   154→      actionTypeList.push(actionType);
   155→      // prettier-ignore
   156→      actionCreatorListBySliceKey[sliceKey] = actionCreatorListBySliceKey[sliceKey] || [];
   157→      actionCreatorsSliceKey[sliceKey] = actionCreatorsSliceKey[sliceKey] || {};
   158→      actionTypesBySliceKey[sliceKey] = actionTypesBySliceKey[sliceKey] || {};
   159→      actionTypesBySliceKey[sliceKey][reducerName] = actionType;
   160→      actionCreatorListBySliceKey[sliceKey].push(action);
   161→      actionCreatorsSliceKey[sliceKey][reducerName] = action;
   162→      return action;
   163→    }
   164→
   165→    if (IsAsyncSliceKind(slice)) {
   166→      AsyncReducerNames.forEach(name => {
   167→        return registerAction(name as StringTypes.SliceReducerName);
   168→      });
   169→
   170→      const fn = function reducer(
   171→        state = slice.initial as MachineState,
   172→        action: MachineAction,
   173→      ) {
   174→        // prettier-ignore
   175→        const localAction = actionCreatorByType[action.type as StringTypes.ActionType];
   176→        if (!localAction) return state;
   177→
   178→        const sliceReducerName = localAction.sliceReducerName;
   179→
   180→        return produce(state, draft => {
   181→          switch (sliceReducerName) {
   182→            case 'load': {
   183→              draft.loading = true;
   184→              draft.failed = false;
   185→              draft.error = null;
   186→              return;
   187→            }
   188→            case 'success': {
   189→              draft.loading = false;
   190→              draft.loaded = true;
   191→              draft.value = action.payload;
   192→              return;
